import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../secret/passwords.txt";
        String basePath = "/var/www/data/";

        // Validate and sanitize user input to prevent path traversal
        if (!userInput.contains("..") && !userInput.contains("//")) {
            String fullPath = basePath + userInput;

            File file = new File(fullPath);

            if (file.exists()) {
                try {
                    byte[] content = Files.readAllBytes(Paths.get(fullPath));
                    System.out.println("File content: " + new String(content));
                } catch (IOException e) {
                    System.err.println("Error reading file: " + e.getMessage());
                }
            } else {
                System.out.println("File does not exist.");
            }
        } else {
            System.out.println("Invalid input detected.");
        }
    }
}

